#include <stdio.h>

int main() {
    int a;
    float b;
    char c;
    if (scanf("%d", &a) != 1) return 0;
    printf("After assigning int: a = %d, b = garbage, c = garbage\n", a);
    if (scanf("%f", &b) != 1) return 0;
    printf("After assigning float: a = garbage, b = %.2f, c = garbage\n", b);
    if (scanf(" %c", &c) != 1) return 0; // leading space skips whitespace
    printf("After assigning char: a = garbage, b = garbage, c = %c\n", c);
    return 0;
}

