code.Java:
import java.io.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line;
        line = br.readLine();
        if (line == null) return;
        int a = Integer.parseInt(line.trim());
        System.out.println("After assigning int: a = " + a + ", b = garbage, c = garbage");
        line = br.readLine();
        if (line == null) return;
        float b = Float.parseFloat(line.trim());
        System.out.printf("After assigning float: a = garbage, b = %.2f, c = garbage\n", b);
        line = br.readLine();
        if (line == null) return;
        char c = line.trim().charAt(0);
        System.out.println("After assigning char: a = garbage, b = garbage, c = " + c);
    }
}

